// Extract alarm details from CloudWatch EventBridge payload
const event = context?.webhook_data || context?.input || {};

// EventBridge CloudWatch Alarm State Change structure
const detail = event.detail || {};
const alarmName = detail.alarmName || event.alarmName || 'demo-5xx-ApiGw5xxAlarm';
const alarmState = (detail.state || {}).value || 'ALARM';
const alarmReason = (detail.state || {}).reason || '';
const previousState = (detail.previousState || {}).value || 'OK';
const alarmTime = (detail.state || {}).timestamp || new Date().toISOString();
const region = event.region || 'us-east-1';

// Extract API GW ID from alarm configuration if available
const configuration = detail.configuration || {};
const metrics = configuration.metrics || [];
let apiGwId = '';
for (const m of metrics) {
  const dims = (m.metricStat || {}).metric?.dimensions || {};
  if (dims.ApiId) { apiGwId = dims.ApiId; break; }
}

return {
  alarm_name: alarmName,
  alarm_state: alarmState,
  previous_state: previousState,
  alarm_time: alarmTime,
  alarm_reason: alarmReason,
  region: region,
  api_gw_id: apiGwId || context?.variables?.api_gw_id || '',
  api_gw_url: context?.variables?.api_gw_url || '',
  validation_start: new Date().toISOString()
};

