// Merge outputs from the 3 parallel validation steps into a single object
function safeJSON(val) {
  if (!val) return {};
  if (typeof val === 'object') return val;
  try { return JSON.parse(val); } catch { return { raw: String(val) }; }
}

const healthOut = safeJSON(context?.steps?.check_health_endpoints?.output?.output);
const metricsOut = safeJSON(context?.steps?.get_cloudwatch_metrics?.output?.output);
const testsOut = safeJSON(context?.steps?.run_integration_tests?.output?.output);
const alarmInfo = safeJSON(context?.steps?.parse_alarm_event?.output);

const healthOverall = healthOut?.overall || 'unknown';
const testsOverall = testsOut?.overall || 'unknown';
const total5xx = metricsOut?.total_5xx_errors ?? 0;

const hasFailure = healthOverall === 'fail' || testsOverall === 'fail' || total5xx > 0;

return {
  health_check: healthOut,
  cloudwatch_metrics: metricsOut,
  integration_tests: testsOut,
  alarm_info: alarmInfo,
  summary: {
    health_overall: healthOverall,
    tests_overall: testsOverall,
    total_5xx_errors: total5xx,
    has_failure: hasFailure,
    validation_time: new Date().toISOString()
  }
};

